URL_FIELD_HELPS = {}


def _base_field_name(name: str) -> str:
    if not name:
        return ""
    parts = name.split("-")
    if len(parts) >= 3 and parts[-2].isdigit():
        return parts[-1]
    return name

def build_help_config(request):
    url_name = getattr(getattr(request, "resolver_match", None), "url_name", None) or ""
    skip = url_name in SKIP_AUTO_HELP_URL_NAMES
    fields = dict(FIELD_HELPS)
    if url_name in URL_FIELD_HELPS:
        fields.update(URL_FIELD_HELPS[url_name])
    return {"skip": skip, "fields": fields, "headers": TABLE_HEADER_HELPS}

def field_help(name: str) -> str:
    return FIELD_HELPS.get(name, "")
